// export default Pipeline;

import React, { useState, useEffect } from "react";

function Pipeline({ loading }) {
  const agents = ["Query Agent", "Router Agent", "Retriever", "Reasoning", "Formatter"];
  const [activeIndex, setActiveIndex] = useState(0);

  useEffect(() => {
    if (!loading) return; // stop if processing is done

    setActiveIndex(0); // start from first agent
    const interval = setInterval(() => {
      setActiveIndex((prev) => {
        if (prev < agents.length - 1) return prev + 1;
        clearInterval(interval);
        return prev;
      });
    }, 1000); // highlight next agent every 1s

    return () => clearInterval(interval);
  }, [loading]);

  return (
    <div className="pipeline-container">
      <div className="pipeline">
        {agents.map((agent, index) => (
          <React.Fragment key={index}>
            <div className={`agent ${index === activeIndex ? "active" : ""}`}>
              {agent}
            </div>
            {index < agents.length - 1 && <div className="arrow">→</div>}
          </React.Fragment>
        ))}
      </div>
      {loading && <div className="thinking">Processing agents...</div>}
    </div>
  );
}

export default Pipeline;
